import asyncio
from dataclasses import dataclass
from datetime import datetime, time as dtime

@dataclass
class WarmPoolSchedule:
    # Desired warm pod count by hour-of-day (local time)
    hourly_min_pods: dict[int, int]
    absolute_min: int = 2  # never drop below this even off-peak

class WarmPoolController:
    def __init__(self, schedule: WarmPoolSchedule, scaler):
        self.schedule = schedule
        self.scaler = scaler  # Kubernetes HPA or cloud autoscaler API

    def desired_warm_count(self) -> int:
        hour = datetime.now().hour
        scheduled = self.schedule.hourly_min_pods.get(hour, self.schedule.absolute_min)
        return max(scheduled, self.schedule.absolute_min)

    async def reconcile(self) -> None:
        desired = self.desired_warm_count()
        current = await self.scaler.get_warm_pod_count()
        if current < desired:
            await self.scaler.scale_to(desired)
            print(f"Warm pool: scaled {current} -> {desired} pods")

    async def run_loop(self, interval_s: int = 60) -> None:
        while True:
            await self.reconcile()
            await asyncio.sleep(interval_s)

# Example schedule: 2 warm pods off-peak, 6 during business hours
schedule = WarmPoolSchedule(
    hourly_min_pods={
        8: 4, 9: 6, 10: 6, 11: 6, 12: 4,
        13: 4, 14: 6, 15: 6, 16: 6, 17: 4,
    },
    absolute_min=2,
)

import time
from dataclasses import dataclass

@dataclass
class BurstQuotaState:
    base_tpm: int             # committed quota
    burst_tpm: int            # burst ceiling (e.g. 2x base)
    burst_window_s: float     # duration burst is allowed (e.g. 60s)
    burst_cooldown_s: float   # required rest after burst (e.g. 300s)
    _burst_started: float = 0.0
    _in_cooldown: bool = False

    def effective_tpm(self, current_tpm: int) -> int:
        now = time.monotonic()

        if self._in_cooldown:
            if now - self._burst_started > self.burst_cooldown_s:
                self._in_cooldown = False
            else:
                return self.base_tpm  # restricted during cooldown

        if current_tpm > self.base_tpm:
            if self._burst_started == 0.0:
                self._burst_started = now
            elapsed = now - self._burst_started
            if elapsed <= self.burst_window_s:
                return self.burst_tpm
            else:
                # Burst window expired — enter cooldown
                self._in_cooldown = True
                return self.base_tpm
        else:
            self._burst_started = 0.0
            return self.base_tpm

state = BurstQuotaState(
