    burst_tpm=1_000_000,
    burst_window_s=60,
    burst_cooldown_s=300,
)

from dataclasses import dataclass
from typing import Optional
import asyncio

@dataclass
class ProviderConfig:
    name: str
    client: object         # provider SDK client
    tpm_limit: int
    quality_tier: int      # 1=best, 2=good, 3=acceptable
    _current_tpm: int = 0

    @property
    def headroom_tpm(self) -> int:
        return max(0, int(self.tpm_limit * 0.85) - self._current_tpm)

class OverflowRouter:
    def __init__(self, providers: list[ProviderConfig]):
        # Sorted by quality: primary first, fallbacks after
        self.providers = sorted(providers, key=lambda p: p.quality_tier)

    async def route(
        self,
        messages: list[dict],
        estimated_tokens: int,
    ) -> dict:
        for provider in self.providers:
            if provider.headroom_tpm >= estimated_tokens:
                provider._current_tpm += estimated_tokens
                try:
                    result = await self._call(provider, messages)
                    return {"result": result, "provider": provider.name}
                except Exception:
                    provider._current_tpm -= estimated_tokens
                    continue  # try next provider
        raise CapacityExhaustedError("All providers at capacity")

    async def _call(self, provider: ProviderConfig, messages: list[dict]) -> str:
        # Dispatch to the provider's SDK (implementation varies by provider)
        raise NotImplementedError

class CapacityExhaustedError(Exception):
    pass

from dataclasses import dataclass
from enum import Enum

class RequestSLA(Enum):
    INTERACTIVE = "interactive"   # must respond < 30s
    BATCH = "batch"               # can wait up to 10 min

@dataclass
class BurstCascade:
    warm_pool: object
    burst_quota: BurstQuotaState
    overflow_router: OverflowRouter
    async_queue: AsyncJobQueue

    async def handle(
        self,
        messages: list[dict],
        estimated_tokens: int,
        sla: RequestSLA,
    ):
        # Layer 1: warm pool
        slot = await self.warm_pool.try_acquire()
        if slot:
            return await slot.infer(messages)

        # Layer 2: provider burst quota
        effective = self.burst_quota.effective_tpm(
            current_tpm=estimated_tokens
        )
        if effective >= estimated_tokens:
            try:
                return await self.overflow_router.route(messages, estimated_tokens)
            except CapacityExhaustedError:
                pass

        # Layer 3: multi-provider fan-out
        try:
            return await self.overflow_router.route(messages, estimated_tokens)
        except CapacityExhaustedError:
            pass

        # Layer 4: async queue or 429
        if sla == RequestSLA.BATCH:
            job_id = await self.async_queue.submit(
                user_id="...", messages=messages
            )
            return {"status": 202, "job_id": job_id}
        else:
            raise RateLimitError("All capacity exhausted. Retry in 30s.")

class RateLimitError(Exception):
    pass

from dataclasses import dataclass
from datetime import datetime, timedelta

@dataclass
class ScalingEvent:
    scheduled_at: datetime
    expected_rps: float
    duration_minutes: int
    label: str

class PreScalingController:
    WARM_UP_LEAD_TIME = timedelta(minutes=10)  # start scaling 10 min early

    def __init__(self, events: list[ScalingEvent], warm_pool: object):
        self.events = sorted(events, key=lambda e: e.scheduled_at)
        self.warm_pool = warm_pool

    def upcoming_events(self, within_minutes: int = 15) -> list[ScalingEvent]:
        now = datetime.utcnow()
        window = now + timedelta(minutes=within_minutes)
        return [e for e in self.events if now <= e.scheduled_at <= window]

    async def tick(self) -> None:
        for event in self.upcoming_events():
            target_pods = self._pods_needed(event.expected_rps)
            await self.warm_pool.scale_to(target_pods)
            print(f"Pre-scale for '{event.label}': {target_pods} pods")

    def _pods_needed(self, rps: float, tokens_per_req: int = 2500) -> int:
        # Each GPU pod handles ~50 TPM sustained for large models
        tpm_needed = rps * 60 * tokens_per_req
        return max(2, int(tpm_needed / 50_000) + 1)
